public class HelloWorld {
    public static void main(String[] args) {
        System.out.println("Hello, World!");
    }
}

// Variables — values can change
int score = 0;
score = 100;  // Updated!

// Constants — values are locked forever
final double PI = 3.14159;
final String APP_NAME = "MyApp";
// PI = 3.14;  // ERROR! Can't change a final

// Naming conventions
int camelCase = 1;           // Variables: camelCase
final int SCREAMING_SNAKE = 2; // Constants: SCREAMING_SNAKE_CASE

import java.util.Scanner;  // Import first!

Scanner scanner = new Scanner(System.in);

System.out.print("What's your name? ");
String name = scanner.nextLine();  // Reads entire line

System.out.print("How old are you? ");
int age = scanner.nextInt();        // Reads just the number

System.out.println("Hi " + name + ", you're " + age + "!");

scanner.close();  // Always close when done!

// Widening (automatic) — small to big is always safe
int myInt = 100;
double myDouble = myInt;  // 100.0, no cast needed

// Narrowing (manual) — big to small needs explicit cast
double pi = 3.14159;
int rounded = (int) pi;   // 3 — decimal part is LOST, not rounded!

// Careful! Overflow happens silently
int big = 130;
byte small = (byte) big;  // -126 (wraps around!)

// Creating strings
String greeting = "Hello";              // Preferred way
String another = new String("Hello");  // Works but wasteful

// Strings are immutable!
String original = "Java";
original.toUpperCase();  // Returns "JAVA" but original is still "Java"!
String upper = original.toUpperCase();  // Now upper is "JAVA"

// Concatenation
String full = "Hello" + " " + "World";  // "Hello World"
int age = 25;
String message = "Age: " + age;          // "Age: 25" (auto-converts)

int x = 5, y = 10;

boolean equal = (x == y);      // false (is x equal to y?)
boolean notEqual = (x != y);   // true (is x different from y?)
boolean greater = (x > y);     // false
boolean less = (x < y);        // true
boolean greaterEq = (x >= 5);  // true (greater OR equal)
boolean lessEq = (y <= 10);    // true

// DANGER with Strings!
String a = "hello";
String b = "hello";
a == b;       // Might be true or false! (compares memory)
a.equals(b);  // Always correctly checks content → true

boolean sunny = true;
boolean warm = false;

// AND — both must be true
boolean perfectDay = sunny && warm;  // false (warm is false)

// OR — at least one must be true  
boolean goOutside = sunny || warm;   // true (sunny is true)

// NOT — flips the value
boolean notSunny = !sunny;           // false

// Combining conditions
int age = 25;
boolean hasLicense = true;
boolean canDrive = (age >= 18) && hasLicense;  // true

// Short-circuit: Java stops early if result is already known
// In (false && something), Java never checks 'something'

int score = 85;

if (score >= 90) {
    System.out.println("A — Excellent!");
} else if (score >= 80) {
    System.out.println("B — Good job!");  // This runs
} else if (score >= 70) {
    System.out.println("C — Passing");
} else {
    System.out.println("F — Keep trying");
}

// Single-line if (no braces needed, but be careful)
if (score == 100) System.out.println("Perfect!");

int age = 20;

// Ternary: condition ? valueIfTrue : valueIfFalse
String status = (age >= 18) ? "Adult" : "Minor";

// Equivalent if-else (more lines)
String status2;
if (age >= 18) {
    status2 = "Adult";
} else {
    status2 = "Minor";
}

// Great for null checks
String name = null;
String display = (name != null) ? name : "Guest";

int day = 3;
String dayName;

switch (day) {
    case 1:
        dayName = "Monday";
        break;  // Don't forget break!
    case 2:
        dayName = "Tuesday";
        break;
    case 3:
        dayName = "Wednesday";
        break;
    case 6:
    case 7:
        dayName = "Weekend!";  // Cases can stack
        break;
    default:
        dayName = "Invalid day";
}

// Java 14+ Enhanced Switch (no break needed!)
String result = switch (day) {
    case 1 -> "Monday";
    case 2 -> "Tuesday";
    case 3 -> "Wednesday";
    case 6, 7 -> "Weekend!";
    default -> "Invalid";
};

String dayType = switch (dayOfWeek) {
    case MONDAY, TUESDAY, WEDNESDAY, THURSDAY, FRIDAY -> "Weekday";
    case SATURDAY, SUNDAY -> "Weekend";
};

// With code blocks (use yield to return value)
int numLetters = switch (day) {
    case MONDAY, FRIDAY, SUNDAY -> 6;
    case TUESDAY -> 7;
    case THURSDAY, SATURDAY -> 8;
    case WEDNESDAY -> {
        System.out.println("Mid-week!");
        yield 9;  // yield returns value from block
    }
};
